import"./ticker-BxUDbM2L.js";import{i as a}from"./country-page-CK6BdUjw.js";import"./utils-Owvk3OYq.js";import"./breadcrumbs-CxxVGuAV.js";a({countryCode:"MA",currency:"MAD",flag:"🇲🇦",nameEn:"Morocco",nameAr:"المغرب",fixedPeg:!1,decimals:2,timezone:"Africa/Casablanca",relatedCountries:[{file:"egypt.html",nameEn:"Egypt",nameAr:"مصر",flag:"🇪🇬"},{file:"jordan.html",nameEn:"Jordan",nameAr:"الأردن",flag:"🇯🇴"},{file:"saudi-arabia.html",nameEn:"Saudi Arabia",nameAr:"السعودية",flag:"🇸🇦"},{file:"uae.html",nameEn:"UAE",nameAr:"الإمارات",flag:"🇦🇪"},{file:"india.html",nameEn:"India",nameAr:"الهند",flag:"🇮🇳"},{file:"kuwait.html",nameEn:"Kuwait",nameAr:"الكويت",flag:"🇰🇼"}],faqEn:[{q:"What is today's gold price in Morocco?",a:"The Moroccan Dirham (MAD) is managed by Bank Al-Maghrib and pegged to a basket of currencies weighted towards the Euro and US Dollar, making it relatively stable. Gold prices in MAD are updated every 90 seconds on this page, reflecting the live XAU/USD spot rate converted at the current MAD exchange rate."},{q:"What karats are popular in Morocco?",a:"18K is the most widely used karat for traditional Moroccan jewellery, including Berber and Arabesque designs. 21K and 22K gold are also available and popular for a higher gold content. Moroccan craftsmanship is renowned for its intricate filigree work, predominantly in 18K."},{q:"Where can I buy gold in Morocco?",a:"The medina of Fes and the souks of Marrakech are Morocco's most celebrated destinations for traditional gold jewellery. Casablanca's Derb Omar market is the main commercial and wholesale hub for gold trading. Major cities like Rabat and Tangier also have well-established gold souks."},{q:"Is gold imported or mined in Morocco?",a:"Morocco imports the vast majority of its gold. While the country has small gold deposits — particularly in the Anti-Atlas and Saharan regions — they are not commercially significant at present. All bullion and most jewellery gold is sourced internationally, meaning local prices closely follow global spot rates."}],faqAr:[{q:"ما هو سعر الذهب اليوم في المغرب؟",a:"يُدار الدرهم المغربي (MAD) من قِبَل بنك المغرب ويرتبط بسلة عملات مرجّحة نحو اليورو والدولار الأمريكي، مما يجعله مستقراً نسبياً. يتم تحديث أسعار الذهب بالدرهم كل 90 ثانية في هذه الصفحة، إذ تعكس سعر XAU/USD الفوري المحوَّل بسعر صرف الدرهم الحالي."},{q:"ما هي العيارات الأكثر شيوعاً في المغرب؟",a:"يُعدّ عيار 18 الأكثر استخداماً في صناعة المجوهرات المغربية التقليدية، بما فيها التصاميم الأمازيغية والأرابيسك. كما يتوفر عيار 21 وعيار 22 ويحظيان بشعبية لمحتواهما المرتفع من الذهب. تتميز الحرفة المغربية بأعمال الفيليغري الدقيقة التي تُنفَّذ أساساً بعيار 18."},{q:"أين يمكنني شراء الذهب في المغرب؟",a:"تُعدّ مدينة فاس القديمة وأسواق مراكش من أبرز الوجهات في المغرب للمجوهرات الذهبية التقليدية. أما سوق درب عمر في الدار البيضاء فيُعدّ المركز التجاري والجملة الرئيسي لتجارة الذهب. كما تضم كل من الرباط وطنجة أسواقاً راسخةً للذهب."},{q:"هل يُستورد الذهب أم يُستخرج محلياً في المغرب؟",a:"يستورد المغرب الجزء الأكبر من ذهبه. وعلى الرغم من وجود رواسب ذهبية صغيرة — لا سيما في منطقة جبال الأطلس الأوسط والمناطق الصحراوية — إلا أنها ليست ذات أهمية تجارية حتى الآن. يُستورد جميع الذهب السبيكي ومعظم ذهب المجوهرات دولياً، مما يجعل الأسعار المحلية تتبع عن كثب أسعار السوق العالمية."}]});
